class Solution:
    def sumOfGoodSubsequences(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        total = 0
        for mask in range(1, 1 << n):
            indices = [i for i in range(n) if mask & (1 << i)]
            good = True
            for a, b in zip(indices, indices[1:]):
                if abs(nums[a] - nums[b]) != 1:
                    good = False
                    break
            if good:
                total += sum(nums[i] for i in indices)
        return total % MOD

