class Solution:
    def sumOfGoodSubsequences(self, nums):
        MOD = 10 ** 9 + 7
        cnt = {}
        sm = {}
        ans = 0
        for x in nums:
            new_count = 1 + cnt.get(x - 1, 0) + cnt.get(x + 1, 0)
            new_sum = x + (sm.get(x - 1, 0) + cnt.get(x - 1, 0) * x) + (sm.get(x + 1, 0) + cnt.get(x + 1, 0) * x)
            new_count %= MOD
            new_sum %= MOD
            cnt[x] = (cnt.get(x, 0) + new_count) % MOD
            sm[x] = (sm.get(x, 0) + new_sum) % MOD
            ans = (ans + new_sum) % MOD
        return ans

