var sumOfGoodSubsequences = function(nums) {
    const MOD = 1000000007n;
    const cnt = new Map();
    const sm = new Map();
    let ans = 0n;
    for (const xRaw of nums) {
        const x = BigInt(xRaw);
        const cntPrev = cnt.get(xRaw - 1) || 0n;
        const cntNext = cnt.get(xRaw + 1) || 0n;
        const smPrev = sm.get(xRaw - 1) || 0n;
        const smNext = sm.get(xRaw + 1) || 0n;
        let newCount = (1n + cntPrev + cntNext) % MOD;
        let newSum = (x + (smPrev + cntPrev * x) + (smNext + cntNext * x)) % MOD;
        cnt.set(xRaw, ((cnt.get(xRaw) || 0n) + newCount) % MOD);
        sm.set(xRaw, ((sm.get(xRaw) || 0n) + newSum) % MOD);
        ans = (ans + newSum) % MOD;
    }
    return Number(ans);
};
